test_code:
assert word_frequency('hello world hello') == {'hello': 2, 'world': 1}
assert word_frequency('') == {}
assert word_frequency('The cat sat on the mat.') == {'the': 2, 'cat': 1, 'sat': 1, 'on': 1, 'mat': 1}
assert word_frequency('Hello, hello, HELLO!') == {'hello': 3}
assert word_frequency('one') == {'one': 1}

assert group_by(len, ['hi', 'bye', 'no', 'yes', 'ok']) == {2: ['hi', 'no', 'ok'], 3: ['bye', 'yes']}
assert group_by(lambda x: x % 2, [1, 2, 3, 4, 5, 6]) == {1: [1, 3, 5], 0: [2, 4, 6]}
assert group_by(str.lower, ['A', 'b', 'a', 'B']) == {'a': ['A', 'a'], 'b': ['b', 'B']}
assert group_by(lambda x: x, []) == {}
